import { useState } from "react";
import { AlertTriangle, RefreshCw, X } from "lucide-react";
import { useMarket } from "@/lib/MarketContext";

const STALE_MS = 7 * 24 * 60 * 60 * 1000;

export default function StaleDataBanner() {
  const { market, loading, refresh } = useMarket();
  const [dismissed, setDismissed] = useState(false);
  const lastUpdatedMs = market?.stats?.lastUpdatedMs;
  if (!lastUpdatedMs || dismissed) return null;
  const ageMs = Date.now() - lastUpdatedMs;
  if (ageMs <= STALE_MS) return null;

  const days = Math.floor(ageMs / (24 * 60 * 60 * 1000));
  const ageLabel = days >= 1 ? `${days} day${days > 1 ? "s" : ""} ago` : "earlier this week";

  return (
    <div
      data-testid="stale-data-banner"
      className="w-full bg-amber-500/[0.08] border border-amber-500/25 rounded-2xl p-4 mt-4 flex items-start gap-3"
      role="status"
    >
      <AlertTriangle className="w-4 h-4 text-amber-400 mt-0.5 shrink-0" />
      <div className="flex-1 min-w-0">
        <div className="font-mono text-[10px] uppercase tracking-[0.18em] text-amber-300 font-bold">
          Data may be out of date
        </div>
        <p className="text-zinc-400 text-sm mt-1 leading-relaxed">
          Last refresh was {ageLabel}. Prices, listings, and seller activity shown here might not match the live market.
        </p>
      </div>
      <div className="flex items-center gap-2 shrink-0">
        <button
          data-testid="stale-data-refresh"
          onClick={refresh}
          disabled={loading.market || loading.sellers}
          className="inline-flex items-center gap-1.5 border border-amber-500/30 hover:border-amber-400/60 hover:text-amber-300 text-amber-200 font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          <RefreshCw className={`w-3 h-3 ${loading.market || loading.sellers ? "animate-spin" : ""}`} /> Refresh
        </button>
        <button
          onClick={() => setDismissed(true)}
          aria-label="Dismiss stale data banner"
          className="text-zinc-500 hover:text-zinc-300 transition-colors p-1"
        >
          <X className="w-4 h-4" />
        </button>
      </div>
    </div>
  );
}
